// Get current user config from SplitInBatches
const user = $('3. SplitInBatches — One User at a Time').item.json;

// Skip inactive users
if (!user['Status'] || user['Status'].trim().toLowerCase() !== 'active') {
  return [];
}

const userName      = user['Name']             || 'Learner';
const userEmail     = user['Email']            || '';
const language      = user['Language']         || 'English';
const difficulty    = user['Difficulty']       || 'Intermediate';
const dailyCount    = parseInt(user['Daily Words Count']) || 5;
const topicFocus    = user['Topic Focus']      || 'General';

if (!userEmail) return [];

// Filter word history for this user + language
const allHistory = $input.all();
const langHistory = allHistory
  .filter(item => {
    const row = item.json;
    return row['Language'] && row['Language'].toLowerCase() === language.toLowerCase()
        && row['User Email'] && row['User Email'].toLowerCase() === userEmail.toLowerCase();
  })
  .map(item => item.json['Word'])
  .filter(Boolean);

// Take last 60 unique words to pass to AI
const recentWords = [...new Set(langHistory)].slice(-60);
const prevWordsStr = recentWords.length > 0
  ? recentWords.join(', ')
  : 'none yet';

// Total words learned (for email header)
const totalLearned = langHistory.length;

return [{ json: {
  user_name: userName,
  user_email: userEmail,
  language,
  difficulty,
  daily_count: dailyCount,
  topic_focus: topicFocus,
  previous_words: prevWordsStr,
  total_learned: totalLearned
}}];

