const raw = $input.first().json.output || $input.first().json.text || '';

let vocab;
try {
  const cleaned = raw.replace(/```json/gi, '').replace(/```/g, '').trim();
  vocab = JSON.parse(cleaned);
} catch (e) {
  throw new Error('Could not parse vocabulary JSON from AI. Raw: ' + raw.slice(0, 300));
}

const userCtx = $('5. Code — Prepare AI Prompt').item.json;
const userName      = userCtx.user_name || 'Learner';
const userEmail     = userCtx.user_email || '';
const language      = userCtx.language || 'English';
const difficulty    = userCtx.difficulty || 'Intermediate';
const totalLearned  = userCtx.total_learned || 0;
const words         = vocab.words || [];
const quiz          = vocab.quiz || [];
const motivational  = vocab.motivational_message || 'Keep learning every day!';
const today         = new Date().toLocaleDateString('en-US', { weekday:'long', month:'long', day:'numeric', year:'numeric' });
const todayISO      = new Date().toISOString().split('T')[0];
const dayNumber     = totalLearned + 1;

const esc = s => String(s||'').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');

// Color scheme per difficulty
const diffColors = {
  'Beginner':     { accent: '#10b981', light: '#f0fdf4', badge: '#d1fae5', badgeText: '#065f46' },
  'Elementary':   { accent: '#3b82f6', light: '#eff6ff', badge: '#dbeafe', badgeText: '#1e40af' },
  'Intermediate': { accent: '#8b5cf6', light: '#f5f3ff', badge: '#ede9fe', badgeText: '#4c1d95' },
  'Advanced':     { accent: '#f59e0b', light: '#fffbeb', badge: '#fef3c7', badgeText: '#78350f' },
  'Expert':       { accent: '#ef4444', light: '#fef2f2', badge: '#fee2e2', badgeText: '#7f1d1d' }
};
const c = diffColors[difficulty] || diffColors['Intermediate'];

// Build word cards HTML
let wordCardsHtml = '';
words.forEach((w, i) => {
  const highlighted = esc(w.example_sentence || '').replace(
    new RegExp('\\b' + esc(w.word || '').replace(/[.*+?^${}()|[\]\\]/g, '\\$&') + '\\b', 'gi'),
    match => `<strong style="color:${c.accent};">${match}</strong>`
  );
  wordCardsHtml += `
  <div style="border:1px solid #e5e7eb;border-radius:10px;margin-bottom:16px;overflow:hidden;">
    <div style="background:${c.accent};padding:12px 16px;display:flex;justify-content:space-between;align-items:center;">
      <div>
        <span style="color:#fff;font-size:20px;font-weight:800;letter-spacing:0.5px;">${esc(w.word)}</span>
        <span style="color:rgba(255,255,255,0.75);font-size:13px;margin-left:10px;">${esc(w.pronunciation)}</span>
      </div>
      <span style="background:rgba(255,255,255,0.2);color:#fff;font-size:11px;padding:3px 10px;border-radius:20px;font-weight:600;">${esc(w.part_of_speech)}</span>
    </div>
    <div style="padding:14px 16px;background:#fff;">
      <p style="font-size:13px;color:#374151;margin:0 0 10px;"><strong style="color:#1f2937;">Definition:</strong> ${esc(w.definition)}</p>
      <div style="background:${c.light};border-left:3px solid ${c.accent};padding:10px 12px;border-radius:0 6px 6px 0;margin-bottom:10px;">
        <p style="font-size:13px;color:#374151;margin:0;"><strong>Example:</strong> ${highlighted}</p>
      </div>
      <div style="background:#f9fafb;border-radius:6px;padding:10px 12px;">
        <p style="font-size:12px;color:#6b7280;margin:0;">&#128161; <strong>Memory Tip:</strong> ${esc(w.memory_tip)}</p>
      </div>
    </div>
  </div>`;
});

// Build quiz HTML
let quizHtml = '';
if (quiz.length > 0) {
  quizHtml = `
  <div style="background:#1e3a5f;border-radius:10px;padding:20px;margin-top:24px;">
    <h3 style="color:#fff;font-size:15px;margin:0 0 16px;">&#129488; Daily Quiz — Test Your Knowledge</h3>`;
  quiz.forEach((q, qi) => {
    quizHtml += `
    <div style="background:rgba(255,255,255,0.05);border-radius:8px;padding:14px;margin-bottom:12px;">
      <p style="color:#e2e8f0;font-size:13px;font-weight:600;margin:0 0 10px;">${qi+1}. ${esc(q.question)}</p>`;
    (q.options || []).forEach(opt => {
      const isCorrect = opt.trim().startsWith(q.correct + ')');
      quizHtml += `<p style="color:${isCorrect ? '#86efac' : '#94a3b8'};font-size:12px;margin:4px 0;padding:6px 10px;background:${isCorrect ? 'rgba(134,239,172,0.1)' : 'transparent'};border-radius:4px;">${esc(opt)}</p>`;
    });
    quizHtml += `<p style="color:#fbbf24;font-size:11px;margin:8px 0 0;">&#10003; ${esc(q.explanation)}</p></div>`;
  });
  quizHtml += `</div>`;
}

// Build full HTML email
const htmlEmail = `<!DOCTYPE html>
<html><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width,initial-scale=1"></head>
<body style="font-family:Arial,sans-serif;max-width:640px;margin:0 auto;background:#f0f4f8;padding:20px;">

  <div style="background:#1e3a5f;padding:24px 28px;border-radius:10px 10px 0 0;">
    <div style="font-size:11px;color:#93c5fd;letter-spacing:1.5px;text-transform:uppercase;margin-bottom:6px;">Daily Vocabulary</div>
    <h1 style="color:#fff;font-size:20px;margin:0 0 4px;">${esc(language)} — Day ${dayNumber}</h1>
    <p style="color:#93c5fd;font-size:12px;margin:0;">${today} &nbsp;•&nbsp; ${words.length} new words &nbsp;•&nbsp; <span style="background:${c.badge};color:${c.badgeText};padding:2px 8px;border-radius:10px;font-weight:700;font-size:11px;">${esc(difficulty)}</span></p>
  </div>

  <div style="background:#fff;padding:20px 24px;">
    <p style="font-size:13px;color:#6b7280;margin:0 0 20px;">Hello ${esc(userName)}! Here are your ${words.length} words for today. ${totalLearned > 0 ? `You have learned <strong style="color:${c.accent};">${totalLearned} words</strong> so far — keep it up!` : 'Welcome to your vocabulary journey!'}</p>

    ${wordCardsHtml}
    ${quizHtml}

    <div style="background:#fffbeb;border-left:4px solid #f59e0b;padding:12px 16px;border-radius:0 6px 6px 0;margin-top:20px;">
      <p style="font-size:13px;color:#92400e;margin:0;">&#127775; ${esc(motivational)}</p>
    </div>
  </div>

  <div style="background:#1e3a5f;padding:12px 24px;border-radius:0 0 10px 10px;text-align:center;">
    <p style="color:#93c5fd;font-size:11px;margin:0;">Vocabulary Builder &nbsp;•&nbsp; Powered by n8n + GPT-4o-mini &nbsp;•&nbsp; ${words.length} words today &nbsp;•&nbsp; ${totalLearned + words.length} total</p>
  </div>

</body></html>`;

// Prepare words to save to history
const wordsToSave = words.map(w => ({
  'Date': todayISO,
  'User Email': userEmail,
  'Language': language,
  'Word': w.word,
  'Definition': w.definition,
  'Example Sentence': w.example_sentence,
  'Difficulty': w.difficulty_tag || difficulty
}));

return [{ json: {
  user_email: userEmail,
  user_name: userName,
  language,
  difficulty,
  word_count: words.length,
  words_to_save: wordsToSave,
  html_email: htmlEmail,
  email_subject: `Your ${language} Words for Today — Day ${dayNumber} (${difficulty})`
}}];

// Spread words_to_save array into individual items for Sheets
// Gmail uses $('7. Code — Format Email and Words').first() for email data
const data = $input.first().json;
const rows = data.words_to_save || [];

if (rows.length === 0) {
  throw new Error('No words to save. Check that AI generated vocabulary correctly.');
}

return rows.map(row => ({ json: row }));
